      const res = await fetch\(url, {
        headers: { 'x-rapidapi-host': 'aerodatabox.p.rapidapi.com', 'x-rapidapi-key': key }
      }\);
      if \(!res.ok\) {
        console.log\(icao + ': HTTP ' + res.status + ' - ' + res.statusText\);
        continue;
      }
      const data = await res.json\(\);
      const arr = \(data.arrivals || []\).length;
      const dep = \(data.departures || []\).length;
      console.log\(icao + ': ' + arr + ' arrivals, ' + dep + ' departures'\);
    } catch\(e\) {
      console.log\(icao + ': ERROR - ' + e.message\);
    }
  }
}\)\(\);
" 2>&1)

